import{_ as i,c as s,o as a,a2 as e}from"./chunks/framework.BCsSUL46.js";const b=JSON.parse('{"title":"硬盘的分区、格式化和挂载","description":"","frontmatter":{},"headers":[],"relativePath":"note/linux/磁盘分区与挂载/磁盘分区.md","filePath":"note/linux/磁盘分区与挂载/磁盘分区.md"}'),t={name:"note/linux/磁盘分区与挂载/磁盘分区.md"},l=e('<h1 id="硬盘的分区、格式化和挂载" tabindex="-1">硬盘的分区、格式化和挂载 <a class="header-anchor" href="#硬盘的分区、格式化和挂载" aria-label="Permalink to &quot;硬盘的分区、格式化和挂载&quot;">​</a></h1><ol><li>对磁盘分区，创建可用partition（类比windows C，D盘符）</li><li>对该partition格式化，创建filesystem （类比windows NTFS）</li><li>创建挂载点</li></ol><h2 id="观察磁盘分区状态" tabindex="-1">观察磁盘分区状态 <a class="header-anchor" href="#观察磁盘分区状态" aria-label="Permalink to &quot;观察磁盘分区状态&quot;">​</a></h2><p><strong>常用命令</strong></p><ul><li><code>lsblk</code> 查看磁盘分区状态(list block devices)</li><li>分区工具 <code>fdisk</code> <code>gdisk</code><strong>example input</strong><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fdisk</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/vdb</span></span></code></pre></div></li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>MBR 分区表请使用 fdisk 分区， GPT 分区 表请使用 gdisk 分区</p></div><ul><li><code>blkid</code> 查看设备UUID等参数</li><li><code>parted</code> 列出磁盘的分区表类型与分区信息 <strong>example input</strong><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">parted</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/vdb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> print</span></span></code></pre></div></li></ul><h2 id="磁盘分区步骤" tabindex="-1">磁盘分区步骤 <a class="header-anchor" href="#磁盘分区步骤" aria-label="Permalink to &quot;磁盘分区步骤&quot;">​</a></h2><ul><li>通过 lsblk 或 blkid 先找到磁盘</li><li>再用 parted /dev/xxx print 来找出内部的分区表类 型</li><li>才用 gdisk 或 fdisk 来操作系统</li></ul><h2 id="创建文件系统" tabindex="-1">创建文件系统 <a class="header-anchor" href="#创建文件系统" aria-label="Permalink to &quot;创建文件系统&quot;">​</a></h2><p><code>mkfs</code> make filesystem CentOS 7 使用 xfs 作为默认文件系统</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkfs.xfs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/vdb1</span></span></code></pre></div><h3 id="文件系统挂载" tabindex="-1">文件系统挂载 <a class="header-anchor" href="#文件系统挂载" aria-label="Permalink to &quot;文件系统挂载&quot;">​</a></h3><p>将文件系统挂载到目录上，目录是文件系统的入口</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><ul><li>单一文件系统不应该被重复挂载在不同的挂载点（目录）中；</li><li>单一目录不应该重复挂载多个文件系统；</li><li>要作为挂载点的目录，理论上应该都是空目录,否则原文件系统下的东西会隐藏</li></ul></div><ul><li><code>mount</code> 挂载文件系统 <strong>example input</strong><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mount</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/vdb1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /mnt</span></span></code></pre></div></li></ul>',16),n=[l];function o(d,p,h,c,r,k){return a(),s("div",null,n)}const g=i(t,[["render",o]]);export{b as __pageData,g as default};
